    private readonly ResetPasswordModel _model = new();
    private bool _isLoading = false;
    private bool _passwordReset = false;
    private string _token = string.Empty;

    protected override void OnInitialized()
    {
        var uri = Navigation.ToAbsoluteUri(Navigation.Uri);
        var query = QueryHelpers.ParseQuery(uri.Query);

        if (query.TryGetValue("token", out var tokenValue))
        {
            _token = tokenValue.ToString();
        }
    }

    private async Task HandleResetPassword()
    {
        if (_model.NewPassword != _model.ConfirmPassword)
        {
            Snackbar.Add("Passwörter stimmen nicht überein", Severity.Error);
            return;
        }

        if (_model.NewPassword.Length < 8)
        {
            Snackbar.Add("Passwort muss mindestens 8 Zeichen lang sein", Severity.Error);
            return;
        }

        try
        {
            _isLoading = true;
            var result = await AuthService.ResetPasswordAsync(_token, _model.NewPassword);

            if (result.IsSuccess)
            {
                _passwordReset = true;
                Snackbar.Add("Passwort erfolgreich zurückgesetzt!", Severity.Success);
            }
            else
            {
                Snackbar.Add($"Fehler beim Zurücksetzen: {result.Error}", Severity.Error);
            }
        }
        catch (Exception ex)
        {
            Snackbar.Add($"Ein Fehler ist aufgetreten: {ex.Message}", Severity.Error);
        }
        finally
        {
            _isLoading = false;
        }
    }

    public class ResetPasswordModel
    {
        public string NewPassword     { get; set; } = string.Empty;
        public string ConfirmPassword { get; set; } = string.Empty;
    }

